UPDATE `skill_content` SET `html_content` = '<p>Zákazník potřeboval zefektivnit proces zadávání objednávek na vytvoření grafických podkladů pro pravidelné sezónní reklamní bannery. Zákazník měl k dispozici tabulku v <strong>Excelu s objednávkami</strong>, které musel ručně přepisovat do FileMakeru, což bylo časově náročné a vznikaly tak i chyby. <strong>Cílem bylo proces automatizovat a urychlit</strong>.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]automatic_order_creation.jpg\" alt=\"Automatizace procesu vytváření objednávek na sezónní reklamní bannery\" /></div>\r\n<p>Implementovali jsme <strong>REST API</strong>, které přijímá data ve formátu JSON. Zákazník tedy ze svého systému přímo odesílá data ve formátu JSON do API<. Díky tomu není potřeba žádná další uživatelská akce, která by celý proces zdržovala, nebo generovala chyby. Toto API <strong>kontroluje validitu JSON souboru</strong>, ověřuje povinné údaje a následně předává ověřená data do FileMaker databáze. Po ověření dat <strong>skript automaticky vytvoří objednávky</strong> do stávající FileMaker aplikace na základě definovaných pravidel.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]automatic_order_creation_diagram.svg\" alt=\"Diagram automatického vytváření objednávek pomocí REST API\" /></div>\r\n<p>Proces, který dříve trval jednotky minut, je nyní díky automatizaci zkrácen na <strong>několik vteřin</strong>. Systém zajišťuje, že všechny objednávky jsou správně <strong>validovány</strong> a zadány do databáze bez manuálních zásahů.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n    <li><a href=\"/cs/filemaker\">FileMaker</a></li>\r\n    <li><a href=\"/fmrestor\">REST API</a></li>\r\n    <li><a href=\"https://www.json.org/json-en.html\" target=\"_blank\">JSON</a></li>\r\n</ul>' WHERE `skill_content`.`id` = 28;
